import{_ as a,o as d,c as r,a2 as e}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F14: 負債結構與償債壓力測試 — 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F14_負債結構與償債壓力測試_投資研究員.md","filePath":"審計報告庫/財務審計/8074_鉅橡/20260501/F14_負債結構與償債壓力測試_投資研究員.md"}'),o={name:"審計報告庫/財務審計/8074_鉅橡/20260501/F14_負債結構與償債壓力測試_投資研究員.md"};function l(i,t,h,n,s,c){return d(),r("div",null,[...t[0]||(t[0]=[e('<p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的投資洞見。</p><h1 id="f14-負債結構與償債壓力測試-—-投資研究員-審計報告" tabindex="-1">F14: 負債結構與償債壓力測試 — 投資研究員 審計報告 <a class="header-anchor" href="#f14-負債結構與償債壓力測試-—-投資研究員-審計報告" aria-label="Permalink to &quot;F14: 負債結構與償債壓力測試 — 投資研究員 審計報告&quot;">​</a></h1><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>負債比率與利息覆蓋倍數為何？債務到期分佈是否集中於短期？在高利率環境下的利息支出承受度為何？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：鉅橡負債比攀升至49.7%，利息保障倍數4.09X，長期借款暴增125%至78.9億，短債佔總債務38%，現金覆蓋短期債務1.16X。在高息環境下具備基本償債能力，但長期借款集中到期構成再融資風險。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年12月31日最新公開數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>負債比率</strong>：112年37.7% → 113年43.9% → 114年49.7%，三年攀升12個百分點，槓桿加速累積。</li><li><strong>利息保障倍數</strong>：112年3.57X → 113年4.06X → 114年4.09X，雖緩升但仍低於5X安全門檻。</li><li><strong>長期借款暴增</strong>：19.9億 → 35.1億 → 78.9億，三年增長294%，非流動負債佔總負債比重從27.7%飆升至51.5%，債務結構由短轉長。</li><li><strong>現金覆蓋短期債務</strong>：61.8億 / 53.06億 = 1.16X，現金對短期借款+一年內到期長期借款的覆蓋率尚可。</li><li><strong>短債佔總債務比</strong>：48.5億 / 1,279億 = 37.9%，短債佔比未過半，但長期借款集中到期（45.5億於114年）構成再融資壓力。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="一、負債比率趨勢-槓桿加速累積" tabindex="-1">一、負債比率趨勢：槓桿加速累積 <a class="header-anchor" href="#一、負債比率趨勢-槓桿加速累積" aria-label="Permalink to &quot;一、負債比率趨勢：槓桿加速累積&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>總資產</th><th>總負債</th><th>負債比率</th></tr></thead><tbody><tr><td>112年</td><td>24.8億</td><td>9.37億</td><td>37.7%</td></tr><tr><td>113年</td><td>28.3億</td><td>12.4億</td><td>43.9%</td></tr><tr><td>114年</td><td>32.8億</td><td>16.3億</td><td>49.7%</td></tr></tbody></table><p>負債比率三年內攀升12個百分點，114年逼近50%警戒線。總負債增加6.93億（+74%），主要驅動來自長期借款暴增58.8億（+167%）。非流動負債佔總負債比重從27.7%飆升至51.5%，顯示公司正積極運用長期槓桿擴張。</p><h3 id="二、利息保障倍數-基本安全但無冗餘" tabindex="-1">二、利息保障倍數：基本安全但無冗餘 <a class="header-anchor" href="#二、利息保障倍數-基本安全但無冗餘" aria-label="Permalink to &quot;二、利息保障倍數：基本安全但無冗餘&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>營業利益</th><th>利息支出</th><th>EBIT</th><th>利息保障倍數 (EBIT/利息)</th></tr></thead><tbody><tr><td>112年</td><td>35.6億</td><td>1.43億</td><td>34.2億</td><td>3.57X</td></tr><tr><td>113年</td><td>40.2億</td><td>1.26億</td><td>38.9億</td><td>4.06X</td></tr><tr><td>114年</td><td>47.8億</td><td>1.58億</td><td>46.2億</td><td>4.09X</td></tr></tbody></table><p>利息保障倍數雖緩升，但仍低於5X的安全門檻。值得注意的是，114年利息支出僅微增0.32億（+25%），遠低於長期借款增幅125%，反映新借入資金尚未完全計息或利率優勢。但隨著78.9億長期借款逐步計息，未來利息負擔將持續攀升。</p><h3 id="三、債務到期分佈-長期借款集中到期風險" tabindex="-1">三、債務到期分佈：長期借款集中到期風險 <a class="header-anchor" href="#三、債務到期分佈-長期借款集中到期風險" aria-label="Permalink to &quot;三、債務到期分佈：長期借款集中到期風險&quot;">​</a></h3><table tabindex="0"><thead><tr><th>年度</th><th>短期借款</th><th>一年內到期長借</th><th>長期借款</th><th>總債務</th><th>短債佔比</th></tr></thead><tbody><tr><td>112年</td><td>40.9億</td><td>0.16億</td><td>20.0億</td><td>60.9億</td><td>67.1%</td></tr><tr><td>113年</td><td>50.3億</td><td>0.33億</td><td>35.1億</td><td>85.7億</td><td>58.7%</td></tr><tr><td>114年</td><td>48.5億</td><td>0.46億</td><td>78.9億</td><td>127.9億</td><td>37.9%</td></tr></tbody></table><p>債務結構已從「短債為主」翻轉為「長債為主」。114年短期借款佔總債務降至37.9%，但長期借款78.9億中，45.5億將於115年到期（佔長期借款57.6%），構成重大再融資壓力。若115年無法以合理利率展延，將面臨流動性緊縮風險。</p><h3 id="四、現金覆蓋與高息壓力測試" tabindex="-1">四、現金覆蓋與高息壓力測試 <a class="header-anchor" href="#四、現金覆蓋與高息壓力測試" aria-label="Permalink to &quot;四、現金覆蓋與高息壓力測試&quot;">​</a></h3><ul><li><strong>現金對短期債務覆蓋率</strong>：61.8億 / (48.5億 + 4.55億) = <strong>1.16X</strong>，現金尚能覆蓋短期債務。</li><li><strong>利率上升100點壓力測試</strong>：以總借款127.9億 × 1% = 額外利息支出1.28億。稅後淨利影響：1.28億 × (1-20%) = 1.02億。以114年EPS 0.54元推算，每股稀釋約<strong>0.08元（-14.8%）</strong>。</li></ul><h3 id="五、綜合評估" tabindex="-1">五、綜合評估 <a class="header-anchor" href="#五、綜合評估" aria-label="Permalink to &quot;五、綜合評估&quot;">​</a></h3><p>鉅橡正處於「積極槓桿化擴張」階段。長期借款三年增長294%，反映公司對未來營運前景的樂觀預期。利息保障倍數4.09X雖低於安全線5X，但仍在可承受範圍。關鍵風險在於78.9億長期借款的到期分佈——若45.5億於115年集中到期且市場利率維持高檔，再融資成本將大幅侵蝕獲利。</p><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><p><strong>空頭風險一：長期借款集中到期引發再融資危機</strong> 114年長期借款78.9億中，45.5億（57.6%）將於115年到期。若當時市場利率維持在高檔（如2.5-3%），以127.9億總債務計，利息支出將從1.58億跳升至3.2-3.8億，利息保障倍數將從4.09X腰斬至2.5-3.0X，逼近B級（利息保障倍數低於3）的危險區間。此為最直接的信用風險觸發點。</p></li><li><p><strong>空頭風險二：利率上升100點的EPS稀釋效應被低估</strong> 壓力測試顯示，若利率上升1%，每股將稀釋0.08元（-14.8%）。考慮到鉅橡的EPS僅0.54元，此稀釋幅度已超過14%。若利率上升200點（從當前高檔再升），EPS可能降至0.3-0.4元區間，引發股東不滿與股價承壓。在高息環境下，此類利率敏感度應被賦予更高權重。</p></li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>計算工具</strong>：財務分析工具.py (cashflow_quality)，參數：8074 2023-2025</li><li><strong>原始數據</strong>：鉅橡企業合併財務報告（112-114年度），年報資料庫 PDF 提取</li><li><strong>查詢參數</strong>：stock_id=8074, 年度112-114（2023-2025）</li><li><strong>關鍵核對碼</strong>：114年總負債1,630,500千元 / 利息支出15,751千元 / 長期借款788,875千元</li></ul>',26)])])}const b=a(o,[["render",l]]);export{u as __pageData,b as default};
